$file = 'lib\messages_screen.dart'
$c = [System.IO.File]::ReadAllText($file, [System.Text.Encoding]::UTF8)
$c = $c -replace "`r`n", "`n"  # normalize
$n = 0

# 1. Update filter & sort logic in _ChatsViewState build
$oldFilterSort = "    // Apply Chip Filter`n    var filtered = _conversations.where((entry) {`n      if (widget.searchQuery.isNotEmpty) {`n        final profile = _profileCache[entry.key];`n        final name = profile?['name'] ?? '';`n        return name.toLowerCase().contains(widget.searchQuery);`n      }`n      `n      if (widget.filter == 'Unread') {`n        // Simple mock for unread: if sender is not me and is_read == false`n        final m = entry.value;`n        return m['sender_id'] != _myUid && m['is_read'] == false;`n      }`n      // Favourites mock`n      if (widget.filter == 'Favourites') {`n        return entry.key.hashCode % 5 == 0; `n      }`n      return true;`n    }).toList();"

$newFilterSort = "    // Apply Chip Filter & Archive Filtering & Pinned sorting`n    var filtered = _conversations.where((entry) {`n      // Filter out archived conversations from main list`n      if (_archivedIds.contains(entry.key)) return false;`n`n      if (widget.searchQuery.isNotEmpty) {`n        final profile = _profileCache[entry.key];`n        final name = profile?['name'] ?? '';`n        return name.toLowerCase().contains(widget.searchQuery);`n      }`n      `n      if (widget.filter == 'Unread') {`n        final isMe = entry.value['sender_id'] == _myUid;`n        final isRead = entry.value['is_read'] == true;`n        final dbUnread = _unreadCounts[entry.key] ?? 0;`n        final isManualUnread = _manuallyUnreadIds.contains(entry.key);`n        final unreadCount = isManualUnread ? 1 : ((!isMe && !isRead) ? dbUnread : 0);`n        return unreadCount > 0;`n      }`n      if (widget.filter == 'Favourites') {`n        return entry.key.hashCode % 5 == 0; `n      }`n      return true;`n    }).toList();`n`n    // Apply sorting: pinned chats first, then maintain recency`n    filtered.sort((a, b) {`n      final aPinned = _pinnedIds.contains(a.key);`n      final bPinned = _pinnedIds.contains(b.key);`n      if (aPinned && !bPinned) return -1;`n      if (!aPinned && bPinned) return 1;`n      return 0;`n    });"

if ($c.Contains($oldFilterSort)) { $c = $c.Replace($oldFilterSort, $newFilterSort); $n++ } else { Write-Host "MISS: filter/sort replacement" }

# 2. Update Archived row onTap to open Archived Chats Screen
$oldArchivedTile = "            if (i == 2) {`n              return ListTile(`n                leading: const Padding(`n                  padding: EdgeInsets.only(left: 8.0, right: 16.0),`n                  child: Icon(Icons.archive_outlined, color: Color(0xFF8B95A5), size: 24),`n                ),`n                title: const Text('Archived', style: TextStyle(color: Colors.white, fontWeight: FontWeight.w600, fontSize: 16)),`n                onTap: () {`n                  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Archive coming soon! 📦')));`n                },`n              );`n            }"

$newArchivedTile = "            if (i == 2) {`n              return ListTile(`n                leading: const Padding(`n                  padding: EdgeInsets.only(left: 8.0, right: 16.0),`n                  child: Icon(Icons.archive_outlined, color: Color(0xFF8B95A5), size: 24),`n                ),`n                title: const Text('Archived', style: TextStyle(color: Colors.white, fontWeight: FontWeight.w600, fontSize: 16)),`n                trailing: _archivedIds.isNotEmpty ? Container(`n                  padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),`n                  decoration: BoxDecoration(color: const Color(0xFF8B95A5).withValues(alpha: 0.2), borderRadius: BorderRadius.circular(12)),`n                  child: Text('\${_archivedIds.length}', style: const TextStyle(color: Colors.white, fontSize: 12, fontWeight: FontWeight.bold)),`n                ) : null,`n                onTap: () async {`n                  await Navigator.push(context, MaterialPageRoute(`n                    builder: (_) => _ArchivedChatsScreen(`n                      archivedIds: _archivedIds,`n                      conversations: _conversations,`n                      profileCache: _profileCache,`n                      unreadCounts: _unreadCounts,`n                      manuallyUnreadIds: _manuallyUnreadIds,`n                      onUnarchive: (id) => setState(() => _archivedIds.remove(id)),`n                    ),`n                  ));`n                  _fetchConversations();`n                },`n              );`n            }"

if ($c.Contains($oldArchivedTile)) { $c = $c.Replace($oldArchivedTile, $newArchivedTile); $n++ } else { Write-Host "MISS: archived tile replacement" }

# 3. Append Archived Chats Screen class at the bottom of the file
$archivedClass = "`n`n// =============================================================================`n// ARCHIVED CHATS SCREEN`n// =============================================================================`nclass _ArchivedChatsScreen extends StatefulWidget {`n  final Set<String> archivedIds;`n  final List<MapEntry<String, Map<String, dynamic>>> conversations;`n  final Map<String, Map<String, String>> profileCache;`n  final Map<String, int> unreadCounts;`n  final Set<String> manuallyUnreadIds;`n  final Function(String) onUnarchive;`n`n  const _ArchivedChatsScreen({`n    required this.archivedIds,`n    required this.conversations,`n    required this.profileCache,`n    required this.unreadCounts,`n    required this.manuallyUnreadIds,`n    required this.onUnarchive,`n  });`n`n  @override`n  State<_ArchivedChatsScreen> createState() => _ArchivedChatsScreenState();`n}`n`nclass _ArchivedChatsScreenState extends State<_ArchivedChatsScreen> {`n  @override`n  Widget build(BuildContext context) {`n    final list = widget.conversations.where((entry) => widget.archivedIds.contains(entry.key)).toList();`n`n    return Scaffold(`n      backgroundColor: const Color(0xFF030305),`n      appBar: AppBar(`n        backgroundColor: const Color(0xFF0D0F14),`n        title: const Text('Archived Chats', style: TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),`n        leading: IconButton(`n          icon: const Icon(Icons.arrow_back_ios_new, color: Colors.white),`n          onPressed: () => Navigator.pop(context),`n        ),`n      ),`n      body: list.isEmpty`n          ? const Center(`n              child: Column(`n                mainAxisAlignment: MainCDATA.center,`n                mainAxisAlignment: MainAxisAlignment.center,`n                children: [`n                  Icon(Icons.archive_outlined, color: Colors.white24, size: 64),`n                  SizedBox(height: 16),`n                  Text('No archived chats', style: TextStyle(color: Colors.white38, fontSize: 16)),`n                ],`n              ),`n            )`n          : ListView.builder(`n              padding: const EdgeInsets.only(top: 8),`n              itemCount: list.length,`n              itemBuilder: (context, i) {`n                final partnerId = list[i].key;`n                final lastMsg = list[i].value;`n                final profile = widget.profileCache[partnerId] ?? {'name': 'User', 'avatar': ''};`n                final name = profile['name']!;`n                final avatar = profile['avatar']!;`n`n                return Dismissible(`n                  key: Key(partnerId),`n                  background: Container(`n                    color: const Color(0xFF3B82F6),`n                    alignment: Alignment.centerLeft,`n                    padding: const EdgeInsets.symmetric(horizontal: 24),`n                    child: const Icon(Icons.unarchive, color: Colors.white, size: 28),`n                  ),`n                  confirmDismiss: (dir) async {`n                    widget.onUnarchive(partnerId);`n                    ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Chat unarchived')));`n                    setState(() {});`n                    return true;`n                  },`n                  child: ListTile(`n                    leading: CircleAvatar(`n                      backgroundImage: avatar.isNotEmpty ? NetworkImage(avatar) : null,`n                      backgroundColor: const Color(0xFF1B202D),`n                      child: avatar.isEmpty ? const Icon(Icons.person, color: Colors.white38) : null,`n                    ),`n                    title: Text(name, style: const TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),`n                    subtitle: Text(`n                      lastMsg['is_image'] == true ? '📸 Photo' : (lastMsg['text'] as String? ?? ''),`n                      style: const TextStyle(color: Colors.white38),`n                      maxLines: 1,`n                      overflow: TextOverflow.ellipsis,`n                    ),`n                    trailing: IconButton(`n                      icon: const Icon(Icons.unarchive, color: Colors.white54),`n                      onPressed: () {`n                        widget.onUnarchive(partnerId);`n                        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Chat unarchived')));`n                        setState(() {});`n                      },`n                    ),`n                  ),`n                );`n              },`n            ),`n    );`n  }`n}"

$c = $c + $archivedClass
$c = $c -replace "`n", "`r`n"  # restore
[System.IO.File]::WriteAllText($file, $c, [System.Text.Encoding]::UTF8)
Write-Host "Done. Applied $n replacements."
